    51→// Authenticate checks that a token exists and is valid, and then removes the token from the
    52→// authorization header in the context.
    53→func (a *authenticator) Authenticate(ctx context.Context) (context.Context, error) {
    54→	return a.tokenAuth(ctx)
    55→}
    56→
    57→const tokenPrefix = "Bearer "
    58→
    59→func (a *authenticator) tokenAuth(ctx context.Context) (context.Context, error) {
    60→	auth, err := extractAuthorization(ctx)
    61→	if err != nil {
    62→		return ctx, err
    63→	}
    64→
    65→	if !strings.HasPrefix(auth, tokenPrefix) {
    66→		return ctx, status.Error(codes.Unauthenticated, `missing "Bearer " prefix in "authorization" value`)
    67→	}
    68→
    69→	token := strings.TrimPrefix(auth, tokenPrefix)
    70→	if token == "" {
    71→		return ctx, status.Error(codes.Unauthenticated, "token required")
    72→	}
    73→
    74→	newCtx := purgeHeader(ctx, "authorization")
    75→
    76→	signedInUser, err := a.getSignedInUser(ctx, token)
    77→	if err != nil {
    78→		a.logger.Warn("request with invalid token", "error", err, "token", token)
    79→		return ctx, status.Error(codes.Unauthenticated, "invalid token")
    80→	}
    81→
    82→	newCtx = a.contextHandler.SetUser(newCtx, signedInUser)
    83→
    84→	return newCtx, nil
    85→}
